Use **`WebApplicationFactory<T>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` that routes directly to it — no real port, no real server.

### Setup

```bash
dotnet add reference ../src/MyMcpServer.csproj
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // Initialize first (required by MCP)
        await InitializeAsync();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(body.GetProperty("result")
                        .GetProperty("isError")
                        .GetBoolean());
    }

    private async Task InitializeAsync()
    {
        var init = new { jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

### Key points

- **No real network** — `WebApplicationFactory` uses an in-memory `TestServer` under the hood.
- **Full pipeline** — middleware, routing, DI, and serialization all run exactly as in production.
- **Override services** — use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks (e.g., fake databases).
- **`Program` must be visible** — add `[assembly: InternalsVisibleTo("YourTestProject")]` or a `public partial class Program { }` in your server project.
- **SSE endpoints** — if your server uses Streamable HTTP (`text/event-stream`), read with `HttpCompletionOption.ResponseHeadersRead` and parse the SSE stream line-by-line.
